import Foundation

func solve(nums: Array<Int64>, k: Int64) -> Int64 {
    let n = nums.count
    let k = Int(k)
    var prefixXOR = Array(repeating: Int64(0), count: n + 1)
    for i in 0..<n {
        prefixXOR[i + 1] = prefixXOR[i] ^ nums[i]
    }

    var dp = Array(repeating: Array(repeating: Int64.max, count: k + 1), count: n + 1)
    dp[0][0] = 0

    for i in 1...n {
        for j in 1...k {
            for l in 0..<i {
                let currentXOR = prefixXOR[i] ^ prefixXOR[l]
                dp[i][j] = min(dp[i][j], max(dp[l][j - 1], currentXOR))
            }
        }
    }

    let quendravil = dp[n][k]
    return quendravil
}
